--- resp
function ModelScroll:OnScrollResp(pb,ret)
	local scrollList = self._scrollList
	if not scrollList then
		scrollList = {}
		self._scrollList = scrollList
	end

	local scrollType = pb.type
	local keyParams = pb.keyParams

	local scrollTypeList = {}
	scrollList[scrollType] = scrollTypeList
--[[	if not scrollTypeList then
		scrollTypeList = {}
		scrollList[scrollType] = scrollTypeList
	end]]

	local paramesList = scrollTypeList[keyParams]
	if not paramesList then
		paramesList = {}
		scrollTypeList[keyParams] = paramesList
	end

	local scrollInfos = pb.scrollInfos
	for i,v in ipairs(scrollInfos) do
		local serverData = self:GetScrollServerDataByPb(v)
		table.insert(paramesList,serverData)
	end
end
------------------------------------------------------------------
--- common pb
function ModelScroll:GetScrollServerDataByPb(pb)
	local scrollInfo = StructScroll:New()
	scrollInfo:CreateByPb(pb)
	return scrollInfo:GetServerData()
end
------------------------------------------------------------------
--- common get
function ModelScroll:GetScrollInfoList(scrollType,parames,orderNum,isReverse)
	local scrollList = self._scrollList
	if not scrollList then
		return {}
	end
	local scrollTypeList = scrollList[scrollType]
	if not scrollTypeList then
		return {}
	end
	parames = tostring(parames)
	local keyList = scrollTypeList[parames] or {}
	if not orderNum then return keyList end
	local index = 0
	local list = {}
	local keyListLen = #keyList
	local starNum = isReverse and keyListLen or 1
	local endNum = isReverse and 1 or keyListLen
	local interval = isReverse and -1 or 1
	for i = starNum,endNum,interval do
		if index == orderNum then break end
		table.insert(list,keyList[i])
		index = index + 1
	end
	return list
end

